const raw = {};
for (const item of $input.all()) {
  raw[item.json.key] = item.json.value;
}

const env = {
  mode: raw.mode,       
  is_live: raw.mode === 'live',
  script_approval_required: raw.script_approval_required === 'true', 
  evrm_token: raw.evrm_token
};

return [{ json: { env } }];

const expansionPrompt = $('Fetch Expansion Prompt').first().json.data;
const script = $('Fetch Scripts to Expand').item.json;
const order = JSON.parse($('Fetch Order Payload').first().json.payload_json);
const child = order.child;

const scriptContent = typeof script.content === 'string'
    ? JSON.parse(script.content)
    : script.content;

const companion = scriptContent.characters?.[0] || {
    name: 'a friendly companion',
    type: 'other',
    appearance: '',
    personality: '',
    connection_to_child: ''
};

const scenesForPrompt = scriptContent.scenes.map(scene => ({
    scene_number: scene.scene_number,
    scene_title: scene.scene_title,
    narration: scene.narration,
    emotion: scene.emotion
}));

const ageReadAloud = child.age <= 5;

// Age-specific reading level guidance — injected as {{reading_level_guidance}}
// Replaces the generic "grade 2-3" line with concrete vocabulary rules per age tier.
// Gives GPT explicit word-choice constraints so it stops defaulting to literary prose.
function getReadingLevelGuidance(age) {
    if (age <= 7) return (
        `- Age ${age} — Grade 1–2 level: very short sentences (5–10 words each). ` +
        `Only words a child this age already knows. ` +
        `Use: "big", "fast", "glowing", "zoomed", "cracked", "laughed". ` +
        `Avoid: "enormous", "vibrant", "luminous", "cascade", "silhouette", "emerged", "beneath". ` +
        `One idea per sentence. Lots of exclamations and short punchy questions.`
    );
    if (age <= 9) return (
        `- Age ${age} — Grade 3–4 level: short-to-medium sentences (8–15 words). ` +
        `Common adventure vocabulary is fine: "glowing", "mysterious", "ancient", "whooshed", "exploded". ` +
        `Avoid adult/literary words: "luminous", "cascade", "silhouette", "ethereal", "emanating", "resplendent". ` +
        `Mix short punchy sentences at exciting moments with slightly longer ones for descriptions.`
    );
    return (
        `- Age ${age} — Grade 4–5 level: varied sentence length for pacing — short bursts at peaks, longer for atmosphere. ` +
        `Adventure vocabulary OK: "ancient", "discovery", "enormous", "vibrating", "mysterious". ` +
        `Still avoid literary/adult prose: "luminous", "cascade", "ethereal", "emanating", "shimmered" (use "glowed"). ` +
        `Use a one-word sentence or fragment for dramatic effect.`
    );
}

const readingLevelGuidance = getReadingLevelGuidance(child.age);

let systemPrompt = expansionPrompt
    .replace('{{child.age}}', child.age)
    .replace('{{child.name}}', child.name)
    .replace('{{child.hero_trait}}', child.hero_trait)
    .replace('{{child.hobby}}', child.hobby)
    .replace('{{child.hobby_detail}}', child.hobby_detail || 'not provided')
    .replace('{{child.signature_look}}', child.signature_look || 'not provided')
    .replace('{{child.recent_win}}', child.recent_win || 'not provided')
    .replace('{{companion.name}}', companion.name)
    .replace('{{companion.type}}', companion.type)
    .replace('{{companion.appearance}}', companion.appearance)
    .replace('{{companion.personality}}', companion.personality)
    .replace('{{companion.connection_to_child}}', companion.connection_to_child)
    .replace('{{reading_level_guidance}}', readingLevelGuidance)
    .replace('{{scenes_json}}', JSON.stringify(scenesForPrompt, null, 2));

const readAloudBlock = /\{\{#if age_read_aloud\}\}([\s\S]*?)\{\{else\}\}([\s\S]*?)\{\{\/if\}\}/;
systemPrompt = systemPrompt.replace(readAloudBlock, (_, readAloudContent, independentContent) => {
    return ageReadAloud ? readAloudContent.trim() : independentContent.trim();
});

const userPrompt = `Expand the story for ${child.name}, age ${child.age}. The companion is ${companion.name} (${companion.type}). Use the approved script above as your backbone.`;

return [{
    json: {
        system_prompt: systemPrompt,
        user_prompt: userPrompt,
        order_id: script.order_id,
        script_version: script.version
    }
}];

// n8n Code node — "Build QA Prompt"
// ─────────────────────────────────────────────────────────────
// Placed in "3.1 EverMagic Scenario Expansion", AFTER:
//   - 'Call OpenAI GPT-4o'      (first story generation)
// Also reads (from earlier in the loop):
//   - 'Build Expansion Prompt'  (original context + prompts)
//   - 'Fetch Order Payload'     (child/companion details)
//   - 'Fetch Scripts to Expand' (current script item)
//   - 'Fetch QA Prompt'         (HTTP GET — expansion_qa.md)
// Feeds into: 'QA Check' (HTTP POST → OpenAI)
// ─────────────────────────────────────────────────────────────

// ── Thresholds (tune here without touching logic) ─────────────
const MIN_SCENE_WORDS    = 200;   // scenes shorter than this are flagged
const MAX_SCENE_WORDS    = 340;   // scenes longer than this are flagged
const MAX_SENTENCE_WORDS = 30;    // sentences over this many words are flagged as dense

// ── Context ───────────────────────────────────────────────────
const context    = $('Build Expansion Prompt').first().json;
const qaTemplate = $('Fetch QA Prompt').first().json.data;  // pure rules, no placeholders

// ── 1. Extract generated story text from OpenAI response ──────
const aiOutput = $input.first().json;
let rawStory;
if (aiOutput.choices?.[0]?.message?.content) {
    rawStory = aiOutput.choices[0].message.content;
} else if (aiOutput.output?.[0]?.content?.[0]?.text) {
    rawStory = aiOutput.output[0].content[0].text;
} else if (aiOutput.message?.content) {
    rawStory = aiOutput.message.content;
} else if (aiOutput.text) {
    rawStory = aiOutput.text;
} else {
    rawStory = JSON.stringify(aiOutput);
}

// ── 2. Hard structural validation ────────────────────────────
// Structural failures are fundamentally different from quality issues.
// If the story JSON is broken, skip real QA and force retry immediately.
let story = null;
let storyValid = false;
let hardFail = false;
let hardFailReason = null;

try {
    story = JSON.parse(rawStory);

    if (!story.scenes || !Array.isArray(story.scenes)) {
        hardFail = true;
        hardFailReason = 'Story output is missing the scenes array entirely.';
    } else if (story.scenes.length !== 5) {
        hardFail = true;
        hardFailReason = `Expected 5 scenes, got ${story.scenes.length}.`;
    } else {
        const missingNarrative = story.scenes.find(s => !s.expanded_narrative);
        if (missingNarrative) {
            hardFail = true;
            hardFailReason = `Scene ${missingNarrative.scene_number} is missing expanded_narrative.`;
        } else {
            storyValid = true;
        }
    }
} catch (_) {
    hardFail = true;
    hardFailReason = 'Story output could not be parsed as JSON. The model may have returned malformed output.';
}

// ── Hard fail shortcut — send dummy request, Parse QA Response will intercept ──
if (hardFail) {
    return [{
        json: {
            request_body: {
                model: 'gpt-4o-mini',
                messages: [{ role: 'user', content: 'Reply with exactly: {"ok":true}' }],
                max_tokens: 10,
                temperature: 0,
            },
            hard_fail:       true,
            hard_fail_reason: hardFailReason,
            story_valid:     false,
            heuristic_flags: [],
            raw_story:       rawStory,
            order_id:        context.order_id,
            script_version:  context.script_version,
        },
    }];
}

// ── 3. Normalize story JSON for consistent QA input ───────────
const normalizedStory = JSON.stringify(story, null, 2);

// ── 4. Heuristic pre-check ────────────────────────────────────
const heuristicFlags = [];

// Word count helpers
function wordCount(text) {
    return text.split(/\s+/).filter(Boolean).length;
}
function sentenceWordCounts(text) {
    return text.split(/[.!?]+/).filter(s => s.trim().length > 0).map(s => wordCount(s));
}

for (const scene of story.scenes) {
    const text  = scene.expanded_narrative;
    const words = wordCount(text);
    const sentWords = sentenceWordCounts(text);
    const denseSentences = sentWords.filter(w => w > MAX_SENTENCE_WORDS).length;

    if (words > MAX_SCENE_WORDS) {
        heuristicFlags.push(`Scene ${scene.scene_number}: too long (${words} words, max ${MAX_SCENE_WORDS})`);
    }
    if (words < MIN_SCENE_WORDS) {
        heuristicFlags.push(`Scene ${scene.scene_number}: too short (${words} words, min ${MIN_SCENE_WORDS})`);
    }
    if (scene.scene_number === 1 && denseSentences > 2) {
        heuristicFlags.push(`Scene 1: ${denseSentences} dense sentences (>${MAX_SENTENCE_WORDS} words each) — possible crowding`);
    }
}

// Child name presence (must appear in at least 3 scenes)
const orderPayload  = JSON.parse($('Fetch Order Payload').first().json.payload_json);
const child         = orderPayload.child;
const scriptRow     = $('Fetch Scripts to Expand').item.json;
const scriptContent = typeof scriptRow.content === 'string'
    ? JSON.parse(scriptRow.content)
    : scriptRow.content;
const companion = scriptContent.characters?.[0] || { name: null };

const childNameLower     = (child.name || '').toLowerCase();
const companionNameLower = (companion.name || '').toLowerCase();

if (childNameLower) {
    const scenesWithChild = story.scenes.filter(s =>
        s.expanded_narrative.toLowerCase().includes(childNameLower)
    ).length;
    if (scenesWithChild < 3) {
        heuristicFlags.push(`Child name "${child.name}" appears in only ${scenesWithChild}/5 scenes`);
    }
}

if (companionNameLower) {
    const scenesWithCompanion = story.scenes.filter(s =>
        s.expanded_narrative.toLowerCase().includes(companionNameLower)
    ).length;
    if (scenesWithCompanion < 3) {
        heuristicFlags.push(`Companion "${companion.name}" appears in only ${scenesWithCompanion}/5 scenes`);
    }
}

// ── 5. Build user message (child context + story) ─────────────
const heuristicBlock = heuristicFlags.length > 0
    ? `\n\nAUTOMATED PRE-CHECK FLAGS (treat as additional evidence when scoring):\n${heuristicFlags.map(f => `• ${f}`).join('\n')}`
    : '';

const userMessage =
`## Story to evaluate

- Child name: ${child.name       || '(not provided)'}
- Child age:  ${child.age        || '(not provided)'}
- Hobby:      ${child.hobby      || '(not provided)'}
- Recent win: ${child.recent_win || '(not provided)'}
- Companion:  ${companion.name   || '(not defined in script)'}

${normalizedStory}${heuristicBlock}

Evaluate the story. Return only the JSON assessment.`;

return [{
    json: {
        request_body: {
            model: 'gpt-4o-mini',
            messages: [
                { role: 'system', content: qaTemplate },
                { role: 'user',   content: userMessage },
            ],
            max_tokens:  600,
            temperature: 0.1,
        },
        hard_fail:       false,
        story_valid:     storyValid,
        raw_story:       rawStory,
        heuristic_flags: heuristicFlags,
        order_id:        context.order_id,
        script_version:  context.script_version,
    },
}];

// n8n Code node — "Parse QA Response"
// ─────────────────────────────────────────────────────────────
// Placed in "3.1 EverMagic Scenario Expansion", AFTER:
//   - 'QA Check' (OpenAI GPT-4o-mini evaluation)
// Also reads:
//   - 'Build QA Prompt' (heuristic flags + raw story + context)
// Feeds into: IF node on 'retry_required'
// ─────────────────────────────────────────────────────────────

const qaContext = $('Build QA Prompt').first().json;

// ── Hard structural failure — short-circuit, no QA needed ─────
if (qaContext.hard_fail === true) {
    return [{
        json: {
            retry_required:     true,
            score:              0,
            effective_score:    0,
            failed_rules:       [{ rule: 'Structure', issue: qaContext.hard_fail_reason }],
            passed_rules:       [],
            retry_instructions: `The story output was structurally invalid: ${qaContext.hard_fail_reason} Regenerate the full story following all output format rules exactly — valid JSON, exactly 5 scenes, each with an expanded_narrative field.`,
            heuristic_flags:    qaContext.heuristic_flags,
            raw_story:          qaContext.raw_story || null,
            order_id:           qaContext.order_id,
            script_version:     qaContext.script_version,
        },
    }];
}

const aiOutput  = $input.first().json;

// ── Extract text from OpenAI response ─────────────────────────
let rawText;
if (aiOutput.choices?.[0]?.message?.content) {
    // Standard OpenAI HTTP API response (used by HTTP Request node)
    rawText = aiOutput.choices[0].message.content;
} else if (aiOutput.output?.[0]?.content?.[0]?.text) {
    // LangChain OpenAI node format
    rawText = aiOutput.output[0].content[0].text;
} else if (aiOutput.message?.content) {
    rawText = aiOutput.message.content;
} else if (aiOutput.text) {
    rawText = aiOutput.text;
} else {
    rawText = JSON.stringify(aiOutput);
}

// Strip markdown fences if model wraps output despite instructions
const cleaned = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i,     '')
    .replace(/```\s*$/,      '')
    .trim();

// ── Parse QA JSON ──────────────────────────────────────────────
let qa;
try {
    qa = JSON.parse(cleaned);
} catch (_) {
    // QA response malformed — pass through without retry to avoid blocking the pipeline
    return [{
        json: {
            retry_required:     false,
            score:              null,
            effective_score:    null,
            failed_rules:       [],
            passed_rules:       [],
            retry_instructions: null,
            qa_parse_error:     true,
            heuristic_flags:    qaContext.heuristic_flags,
            raw_story:          qaContext.raw_story,
            order_id:           qaContext.order_id,
            script_version:     qaContext.script_version,
        },
    }];
}

// ── Effective score: multiple heuristic flags push borderline scores down ──
const heuristicCount = (qaContext.heuristic_flags || []).length;
const effectiveScore = heuristicCount >= 2 ? Math.min(qa.score, 7) : qa.score;
const retryRequired  = qa.retry_required === true || effectiveScore < 8;

return [{
    json: {
        retry_required:     retryRequired,
        score:              qa.score,
        effective_score:    effectiveScore,
        failed_rules:       qa.failed_rules    || [],
        passed_rules:       qa.passed_rules    || [],
        retry_instructions: qa.retry_instructions || null,
        heuristic_flags:    qaContext.heuristic_flags,
        raw_story:          qaContext.raw_story,
        order_id:           qaContext.order_id,
        script_version:     qaContext.script_version,
    },
}];

// n8n Code node — "Build Retry Prompt"
// ─────────────────────────────────────────────────────────────
// Placed in "3.1 EverMagic Scenario Expansion", AFTER:
//   - IF node (retry_required = true branch)
// Also reads:
//   - 'Build Expansion Prompt' (original system + user prompts)
//   - 'Parse QA Response'      (score, failed rules, retry instructions)
// Feeds into: 'Retry GPT-4o' (second story generation call)
// ─────────────────────────────────────────────────────────────

const originalContext = $('Build Expansion Prompt').first().json;
const qaResult        = $('Parse QA Response').first().json;

// ── Build failed rules text ────────────────────────────────────
const failedRulesText = (qaResult.failed_rules || [])
    .map(f => `• ${f.rule}: ${f.issue}`)
    .join('\n') || 'See revision instructions below.';

const heuristicText = (qaResult.heuristic_flags || []).length > 0
    ? `\nAuto-detected structural issues:\n${qaResult.heuristic_flags.map(f => `• ${f}`).join('\n')}\n`
    : '';

// ── Append QA feedback block to the original system prompt ────
const feedbackBlock = `

---

## Quality Control Feedback — Revision Required

This story was evaluated and scored ${qaResult.score}/10. Minimum required: 8.
${heuristicText}
Rules that failed:
${failedRulesText}

## Revision Instructions

${qaResult.retry_instructions}

---

Rewrite the ENTIRE story following ALL original rules above PLUS all revision instructions.
Do NOT reuse sentences from the previous attempt — start fresh.
Return the same JSON structure. No markdown fences. No commentary. Only the JSON.`;

return [{
    json: {
        request_body: {
            model: 'gpt-4o',
            messages: [
                {
                    role:    'system',
                    content: originalContext.system_prompt + feedbackBlock,
                },
                {
                    role:    'user',
                    content: originalContext.user_prompt,
                },
            ],
            max_tokens:  4000,
            temperature: 0.75,
        },
        order_id:       qaResult.order_id,
        script_version: qaResult.script_version,
        qa_score:       qaResult.score,
    },
}];

// n8n Code node — "Parse Expansion Response"
// Placed AFTER the OpenAI node in the Scenario Expansion workflow
// Extracts and validates the expanded scenario JSON from GPT-4o output

// ─────────────────────────────────────────────────────────────
// 1. Pick the better story — original vs retry
// ─────────────────────────────────────────────────────────────

const firstScore = $('Parse QA Response').first().json.score  ?? 0;
const retryScore = $('Parse QA Response 2').first().json.score ?? 0;
const useRetry   = retryScore > firstScore;

let rawText;
if (useRetry) {
    // Retry scored higher — use it
    rawText = $('Retry GPT-4o').first().json.choices[0].message.content;
} else {
    // Original was equal or better — use it
    rawText = $('Parse QA Response').first().json.raw_story;
}

// ─────────────────────────────────────────────────────────────
// 2. Parse JSON
// ─────────────────────────────────────────────────────────────

const expanded = JSON.parse(rawText);

// ─────────────────────────────────────────────────────────────
// 3. Validate structure
// ─────────────────────────────────────────────────────────────

if (!expanded.scenes || expanded.scenes.length !== 5) {
    throw new Error(`Expected 5 scenes, got ${expanded.scenes?.length ?? 0}`);
}

for (const scene of expanded.scenes) {
    if (!scene.expanded_narrative) {
        throw new Error(`Scene ${scene.scene_number} is missing expanded_narrative`);
    }
}

// ─────────────────────────────────────────────────────────────
// 4. Pass through with context from Build Expansion Prompt node
// ─────────────────────────────────────────────────────────────

const context = $('Build Expansion Prompt').first().json;

// qa_score = first attempt score (from Build Retry Prompt context)
// qa_score_retry = second attempt score (from Parse QA Response 2, after retry)
let qaScore = null;
let qaScoreRetry = null;
try { qaScore      = $('Build Retry Prompt').first().json.qa_score         ?? null; } catch (_) {}
try { qaScoreRetry = $('Parse QA Response 2').first().json.score           ?? null; } catch (_) {}

return [{
    json: {
        order_id:         context.order_id,
        script_version:   context.script_version,
        expanded_content: expanded,
        qa_score:         qaScore,
        qa_score_retry:   qaScoreRetry,
    }
}];

// n8n Code node — "Accept Story"
// ─────────────────────────────────────────────────────────────
// Placed in "3.1 EverMagic Scenario Expansion" on the QA PASS path:
//   IF retry_required = FALSE → this node
// Reads:
//   - 'Parse QA Response' (raw_story, score, order_id, script_version)
// Returns the same shape as 'Parse Expansion Response' so both
// branches can feed identical Save + Update Status nodes.
// ─────────────────────────────────────────────────────────────

const qaResult = $('Parse QA Response').first().json;

const expanded = JSON.parse(qaResult.raw_story);

if (!expanded.scenes || expanded.scenes.length !== 5) {
    throw new Error(`Expected 5 scenes, got ${expanded.scenes?.length ?? 0}`);
}

return [{
    json: {
        order_id:         qaResult.order_id,
        script_version:   qaResult.script_version,
        expanded_content: expanded,
        qa_score:         qaResult.score,
        qa_score_retry:   null,   // no retry was needed
    },
}];

// n8n Code node — "Build QA Prompt"
// ─────────────────────────────────────────────────────────────
// Placed in "3.1 EverMagic Scenario Expansion", AFTER:
//   - 'Call OpenAI GPT-4o'      (first story generation)
// Also reads (from earlier in the loop):
//   - 'Build Expansion Prompt'  (original context + prompts)
//   - 'Fetch Order Payload'     (child/companion details)
//   - 'Fetch Scripts to Expand' (current script item)
//   - 'Fetch QA Prompt'         (HTTP GET — expansion_qa.md)
// Feeds into: 'QA Check' (HTTP POST → OpenAI)
// ─────────────────────────────────────────────────────────────

